# Inspect the public API surface of the M.E.AI assemblies
cd /tmp/sv-ef441681d5a545ff80de4d74b7835ad0/ResearchAgent

# Write a quick inspection script
cat > /tmp/inspect_api.csx << 'CSEOF'
using System.Reflection;

var meaiPath = Directory.GetFiles(
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/microsoft.extensions.ai/10.6.0"),
    "Microsoft.Extensions.AI.dll", SearchOption.AllDirectories).First(f => f.Contains("net9.0"));

var meaiAbsPath = Directory.GetFiles(
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/microsoft.extensions.ai.abstractions"),
    "Microsoft.Extensions.AI.Abstractions.dll", SearchOption.AllDirectories).Where(f => f.Contains("net9.0")).OrderByDescending(f => f).First();

var openaiPath = Directory.GetFiles(
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/microsoft.extensions.ai.openai"),
    "Microsoft.Extensions.AI.OpenAI.dll", SearchOption.AllDirectories).Where(f => f.Contains("net9.0")).OrderByDescending(f => f).First();

Console.WriteLine($"MEAI: {meaiPath}");
Console.WriteLine($"MEAI Abstractions: {meaiAbsPath}");
Console.WriteLine($"MEAI OpenAI: {openaiPath}");
CSEOF

# Instead, let me use dotnet to check types via a test program
cat > /tmp/check_api.cs << 'CSEOF'
// Quick check of available types
using Microsoft.Extensions.AI;

// See if IChatClient has GetResponseAsync or CompleteAsync
var methods = typeof(IChatClient).GetMethods();
foreach (var m in methods)
    Console.WriteLine($"IChatClient.{m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
CSEOF

# Use the project itself to check
cat > /tmp/sv-ef441681d5a545ff80de4d74b7835ad0/ResearchAgent/Program.cs << 'EOF'
using System.Reflection;
using Microsoft.Extensions.AI;

// Check IChatClient methods
Console.WriteLine("=== IChatClient methods ===");
foreach (var m in typeof(IChatClient).GetMethods())
    Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check ChatClientBuilderExtensions / UseFunctionInvocation
Console.WriteLine("\n=== ChatClientBuilder methods ===");
foreach (var m in typeof(ChatClientBuilder).GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.DeclaringType != typeof(object)))
    Console.WriteLine($"  {m.Name}");

// Check AIFunctionFactory
Console.WriteLine("\n=== AIFunctionFactory methods ===");
foreach (var m in typeof(AIFunctionFactory).GetMethods(BindingFlags.Public | BindingFlags.Static))
    Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check ChatOptions properties
Console.WriteLine("\n=== ChatOptions properties ===");
foreach (var p in typeof(ChatOptions).GetProperties())
    Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");

// Check extension methods on OpenAI ChatClient
var openaiAsmTypes = AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.GetName().Name?.Contains("OpenAI") == true || a.GetName().Name?.Contains("Extensions.AI") == true)
    .SelectMany(a => { try { return a.GetTypes(); } catch { return []; } })
    .Where(t => t.IsPublic && t.IsAbstract && t.IsSealed) // static classes = extension methods
    .ToList();

Console.WriteLine("\n=== Extension method classes ===");
foreach (var t in openaiAsmTypes)
{
    var exts = t.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.IsDefined(typeof(System.Runtime.CompilerServices.ExtensionAttribute), false))
        .Where(m => m.Name.Contains("Chat") || m.Name.Contains("AsChat") || m.Name.Contains("AsChatClient") || m.Name.Contains("AsIChatClient"))
        .ToList();
    if (exts.Count > 0)
    {
        Console.WriteLine($"  {t.FullName}:");
        foreach (var m in exts)
            Console.WriteLine($"    {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}

// Check ChatRole
Console.WriteLine("\n=== ChatRole static fields ===");
foreach (var f in typeof(ChatRole).GetProperties(BindingFlags.Public | BindingFlags.Static))
    Console.WriteLine($"  {f.Name}");

// Check ChatMessage constructors
Console.WriteLine("\n=== ChatMessage constructors ===");
foreach (var c in typeof(ChatMessage).GetConstructors())
    Console.WriteLine($"  ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check ChatResponse or ChatCompletion
Console.WriteLine("\n=== Types containing 'Response' or 'Completion' ===");
var types = AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.GetName().Name?.Contains("Extensions.AI") == true)
    .SelectMany(a => { try { return a.GetTypes(); } catch { return []; } })
    .Where(t => t.IsPublic && (t.Name.Contains("Response") || t.Name.Contains("Completion") || t.Name.Contains("Chat")))
    .Select(t => t.FullName)
    .Distinct()
    .OrderBy(n => n)
    .ToList();
foreach (var t in types)
    Console.WriteLine($"  {t}");
EOF

