using System.Reflection;
using Microsoft.Extensions.AI;

// Find extension methods for creating IChatClient from OpenAI
var allExtMethods = AppDomain.CurrentDomain.GetAssemblies()
    .SelectMany(a => { try { return a.GetTypes(); } catch { return []; } })
    .Where(t => t.IsPublic && t.IsAbstract && t.IsSealed)
    .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
    .Where(m => m.IsDefined(typeof(System.Runtime.CompilerServices.ExtensionAttribute), false))
    .Where(m => {
        var pType = m.GetParameters().FirstOrDefault()?.ParameterType;
        return pType != null && (pType.FullName?.Contains("OpenAI") == true || pType.FullName?.Contains("ChatClient") == true);
    })
    .ToList();

Console.WriteLine("=== Extension methods on OpenAI types ===");
foreach (var m in allExtMethods)
    Console.WriteLine($"  {m.DeclaringType?.FullName}.{m.Name}(this {m.GetParameters()[0].ParameterType.Name}, ...) -> {m.ReturnType.Name}");

// Check FunctionInvokingChatClient
Console.WriteLine("\n=== FunctionInvokingChatClientBuilderExtensions methods ===");
foreach (var m in typeof(FunctionInvokingChatClientBuilderExtensions).GetMethods(BindingFlags.Public | BindingFlags.Static))
    Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check ChatResponse properties
Console.WriteLine("\n=== ChatResponse properties ===");
foreach (var p in typeof(ChatResponse).GetProperties())
    Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");

