using System.ComponentModel;
using System.Text.RegularExpressions;
using System.Web;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build the chat client with automatic tool / function invocation
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Register tools the agent can call
// ---------------------------------------------------------------------------
var notebook = new ResearchNotebook();

List<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// ---------------------------------------------------------------------------
// Prompt the user for a research topic
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍  Researching: {topic}\n");

// ---------------------------------------------------------------------------
// Run the research agent
// ---------------------------------------------------------------------------
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your job is to research a topic using the tools
        provided and then deliver a clear, well-structured summary.

        Follow this workflow:
          1. SearchWeb – run at least 2-3 searches with varied queries to get
             broad coverage of the topic.
          2. SaveNote – after each search, save the most important findings
             as a note (include source details when available).
          3. GetNotes – once you have gathered enough material, retrieve all
             your notes and compose a comprehensive summary.

        Be factual and cite sources where possible.
        """),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}"),
];

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine();
Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine("  📋  Research Summary");
Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

// ===========================================================================
//  Tool: Web Search  (DuckDuckGo Lite – no API key needed)
// ===========================================================================
static partial class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information and return a list of result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐  Searching: \"{query}\"");

        try
        {
            var url = $"https://lite.duckduckgo.com/lite?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var snippets = ParseSnippets(html);

            if (snippets.Count == 0)
                return $"No results found for \"{query}\". Try a different query.";

            return $"Results for \"{query}\":\n" +
                   string.Join("\n", snippets.Select((s, i) => $"  [{i + 1}] {s}"));
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). Try a different query.";
        }
    }

    private static List<string> ParseSnippets(string html)
    {
        // DuckDuckGo Lite returns snippets in <td class="result-snippet"> elements
        return SnippetPattern().Matches(html)
            .Select(m => StripHtml(HttpUtility.HtmlDecode(m.Groups[1].Value)))
            .Where(s => s.Length > 0)
            .Take(6)
            .ToList();
    }

    private static string StripHtml(string? value) =>
        string.IsNullOrEmpty(value) ? "" : HtmlTagPattern().Replace(value, "").Trim();

    [GeneratedRegex("""<td\s+class="result-snippet">(.*?)</td>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetPattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagPattern();
}

